// MARK: - Promo Code Validator

final class PromoCodeValidator {
    
    private static let allowedCodeCharacters = CharacterSet.alphanumerics
    private static let minCodeLength = 3
    private static let maxCodeLength = 30
    private static let minDiscount = 1
    private static let maxDiscount = 100
    
    static func sanitizeCode(_ code: String) -> String {
        let trimmed = code.trimmingCharacters(in: .whitespacesAndNewlines)
        let filtered = trimmed.unicodeScalars.filter { allowedCodeCharacters.contains($0) }
        return String(String.UnicodeScalarView(filtered)).uppercased()
    }
    
    static func validateCode(_ code: String) throws -> String {
        let sanitized = sanitizeCode(code)
        
        guard !sanitized.isEmpty else {
            throw PromoError.missingPromoCode
        }
        
        guard sanitized.count >= minCodeLength, sanitized.count <= maxCodeLength else {
            throw PromoError.promoCodeInvalidFormat
        }
        
        return sanitized
    }
    
    static func validateDiscount(_ discountString: String) throws -> Int {
        let trimmed = discountString.trimmingCharacters(in: .whitespacesAndNewlines)
        
        guard let discount = Int(trimmed) else {
            throw PromoError.invalidDiscount
        }
        
        guard discount >= minDiscount, discount <= maxDiscount else {
            throw PromoError.discountOutOfRange
        }
        
        return discount
    }
}

// MARK: - Rate Limiter

final class RateLimiter {
    private var attempts: [String: [Date]] = [:]
    private let maxAttempts: Int
    private let windowSeconds: TimeInterval
    private let queue = DispatchQueue(label: "com.myapp.ratelimiter", attributes: .concurrent)
    
    init(maxAttempts: Int = 5, windowSeconds: TimeInterval = 300) {
        self.maxAttempts = maxAttempts
        self.windowSeconds = windowSeconds
    }
    
    func shouldAllow(identifier: String) -> Bool {
        var result = false
        queue.sync {
            let now = Date()
            let windowStart = now.addingTimeInterval(-windowSeconds)
            let recentAttempts = (attempts[identifier] ?? []).filter { $0 > windowStart }
            result = recentAttempts.count < maxAttempts
        }
        return result
    }
    
    func recordAttempt(identifier: String) {
        queue.async(flags: .barrier) {
            let now = Date()
            let windowStart = now.addingTimeInterval(-self.windowSeconds)
            var existing = (self.attempts[identifier] ?? []).filter { $0 > windowStart }
            existing.append(now)
            self.attempts[identifier] = existing
        }
    }
}

// MARK: - Universal Link Parser

final class UniversalLinkParser {
    
    private static let allowedHosts = ["myapp.com", "www.myapp.com"]
    private static let promoPath = "/promo"
    
    struct PromoLinkData {
        let code: String
        let discount: Int
    }
    
    static func parsePromoLink(from url: URL) throws -> PromoLinkData {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            throw PromoError.invalidURL
        }
        
        guard let host = components.host?.lowercased(),
              allowedHosts.contains(host) else {
            throw PromoError.invalidURL
        }
        
        guard components.path.lowercased() == promoPath else {
            throw PromoError.invalidURL
        }
        
        guard let scheme = components.scheme?.lowercased(),
              scheme == "https" else {
            throw PromoError.invalidURL
        }
        
        let queryItems = components.queryItems ?? []
        
        guard let codeParam = queryItems.first(where: { $0.name == "code" })?.value,
              !codeParam.isEmpty else {
            throw PromoError.missingPromoCode
        }
        
        guard let discountParam = queryItems.first(where: { $0.name == "discount" })?.value,
              !discountParam.isEmpty else {
            throw PromoError.missingDiscount
        }
        
        let validatedCode = try PromoCodeValidator.validateCode(codeParam)
        let validatedDiscount = try PromoCodeValidator.validateDiscount(discountParam)
        
        return PromoLinkData(code: validatedCode, discount: validatedDiscount)
    }
}

// MARK: - Promo Service Protocol

protocol PromoServiceProtocol {
    func validateAndApplyPromo(code: String, discount: Int, completion: @escaping (Result<PromoApplicationResult, PromoError>) -> Void)
}

// MARK: - Promo Service

final class PromoService: PromoServiceProtocol {
    
    private let rateLimiter = RateLimiter(maxAttempts: 5, windowSeconds: 300)
    private let session: URLSession
    private let baseURL: String
    
    init(baseURL: String = "https://api.myapp.com") {
        let configuration = URLSessionConfiguration.default
        configuration.tlsMinimumSupportedProtocolVersion = .TLSv12
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        self.session = URLSession(configuration: configuration)
        self.baseURL = baseURL
    }
    
    func validateAndApplyPromo(code: String, discount: Int, completion: @escaping (Result<PromoApplicationResult, PromoError>) -> Void) {
        
        guard let userId = getCurrentUserId() else {
            completion(.failure(.userNotAuthenticated))
            return
        }
        
        let rateLimitKey = "promo_\(userId)"
        guard rateLimiter.shouldAllow(identifier: rateLimitKey) else {
            completion(.failure(.rateLimitExceeded))
            return
        }
        rateLimiter.recordAttempt(identifier: rateLimitKey)
        
        do {
            let validatedCode = try PromoCodeValidator.validateCode(code)
            let validatedDiscount = try PromoCodeValidator.validateDiscount(String(discount))
            
            sendPromoToServer(code: validatedCode, discount: validatedDiscount, userId: userId, completion: completion)
        } catch let error as PromoError {
            completion(.failure(error))
        } catch {
            completion(.failure(.serverError(error.localizedDescription)))
        }
    }
    
    private func sendPromoToServer(code: String, discount: Int, userId: String, completion: @escaping (Result<PromoApplicationResult, PromoError>) -> Void) {
        
        guard let url = URL(string: "\(baseURL)/v1/promo/apply") else {
            completion(.failure(.serverError("Invalid server URL")))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        if let authToken = getAuthToken() {
            request.setValue("Bearer \(authToken)", forHTTPHeaderField: "Authorization")
        }
        
        let requestBody: [String: Any] = [
            "promo_code": code,
            "claimed_discount": discount,
            "user_id": userId,
            "timestamp": ISO8601DateFormatter().string(from: Date()),
            "platform": "ios",
            "app_version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "unknown"
        ]
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: requestBody)
        } catch {
            completion(.failure(.serverError("Failed to encode request")))
            return
        }
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                DispatchQueue.main.async {
                    completion(.failure(.networkError(error)))
                }
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                DispatchQueue.main.async {
                    completion(.failure(.serverError("Invalid response")))
                }
                return
            }
            
            guard let data = data else {
                DispatchQueue.main.async {
                    completion(.failure(.serverError("No data received")))
                }
                return
            }
            
            DispatchQueue.main.async {
                self.handleServerResponse(statusCode: httpResponse.statusCode, data: data, completion: completion)
            }
        }
        task.resume()
    }
    
    private func handleServerResponse(statusCode: Int, data: Data, completion: @escaping (Result<PromoApplicationResult, PromoError>) -> Void) {
        
        switch statusCode {
        case 200:
            do {
                if let json = try JSONSerialization.jsonObject(with: data) as? [String: Any] {
                    let appliedDiscount = json["applied_discount"] as? Int
                    let message = json["message"] as? String ?? "Promo code applied successfully!"
                    let promoCode = json["promo_code"] as? String
                    
                    let result = PromoApplicationResult(
                        success: true,
                        message: message,
                        appliedDiscount: appliedDiscount,
                        promoCode: promoCode
                    )
                    completion(.success(result))
                } else {
                    completion(.failure(.serverError("Invalid response format")))
                }
            } catch {
                completion(.failure(.serverError("Failed to parse response")))
            }
            
        case 400:
            let message = parseErrorMessage(from: data) ?? "Invalid promo code."
            completion(.failure(.serverError(message)))
            
        case 401:
            completion(.failure(.userNotAuthenticated))
            
        case 404:
            completion(.failure(.promoCodeInvalidFormat))
            
        case 409:
            completion(.failure(.promoCodeAlreadyUsed))
            
        case 410:
            completion(.failure(.promoCodeExpired))
            
        case 429:
            completion(.failure(.rateLimitExceeded))
            
        default:
            let message = parseErrorMessage(from: data) ?? "An unexpected error occurred."
            completion(.failure(.serverError(message)))
        }
    }
    
    private func parseErrorMessage(from data: Data) -> String? {
        if let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] {
            return json["error"] as? String ?? json["message"] as? String
        }
        return nil
    }
    
    private func getCurrentUserId() -> String? {
        return UserDefaults.standard.string(forKey: "authenticated_user_id")
    }
    
    private func getAuthToken() -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: "auth_token",
            kSecAttrService as String: "com.myapp.auth",
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            return nil
        }
        
        return String(data: data, encoding: .utf8)
    }
}

// MARK: - Promo Coordinator

final class PromoCoordinator {
    
    private let promoService: PromoServiceProtocol
    private var pendingPromoData: UniversalLinkParser.PromoLinkData?
    
    init(promoService: PromoServiceProtocol = PromoService()) {
        self.promoService = promoService
    }
    
    func handleUniversalLink(_ url: URL, from viewController: UIViewController) {
        do {
            let promoData = try UniversalLinkParser.parsePromoLink(from: url)
            
            logPromoLinkReceived(code: promoData.code, discount: promoData.discount)
            
            showConfirmation(for: promoData, from: viewController)
            
        } catch let error as PromoError {
            showError(error, from: viewController)
        } catch {
            showError(PromoError.invalidURL, from: viewController)
        }
    }
    
    func handlePendingPromo(from viewController: UIViewController) {
        guard let promoData = pendingPromoData else { return }
        pendingPromoData = nil
        showConfirmation(for: promoData, from: viewController)
    }
    
    private func showConfirmation(for promoData: UniversalLinkParser.PromoLinkData, from viewController: UIViewController) {
        let alert = UIAlertController(
            title: "Promo Code Found!",
            message: "Apply promo code \(promoData.code) for \(promoData.discount)% off?",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Apply", style: .default) { [weak self] _ in
            self?.applyPromo(promoData, from: viewController)
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        viewController.present(alert, animated: true)
    }
    
    private func applyPromo(_ promoData: UniversalLinkParser.PromoLinkData, from viewController: UIViewController) {
        let loadingAlert = UIAlertController(title: nil, message: "Applying promo code...", preferredStyle: .alert)
        let indicator = UIActivityIndicatorView(style: .medium)
        indicator.translatesAutoresizingMaskIntoConstraints = false
        indicator.startAnimating()
        loadingAlert.view.addSubview(indicator)
        NSLayoutConstraint.activate([
            indicator.centerXAnchor.constraint(equalTo: loadingAlert.view.centerXAnchor),
            indicator.bottomAnchor.constraint(equalTo: loadingAlert.view.bottomAnchor, constant: -20)
        ])
        
        viewController.present(loadingAlert, animated: true)
        
        promoService.validateAndApplyPromo(code: promoData.code, discount: promoData.discount) { [weak self] result in
            loadingAlert.dismiss(animated: true) {
                switch result {
                case .success(let applicationResult):
                    self?.showSuccess(applicationResult, from: viewController)
                case .failure(let error):
                    if case .userNotAuthenticated = error {
                        self?.pendingPromoData = promoData
                        self?.promptLogin(from: viewController)
                    } else {
                        self?.showError(error, from: viewController)
                    }
                }
            }
        }
    }
    
    private func showSuccess(_ result: PromoApplicationResult, from viewController: UIViewController) {
        let discountText = result.appliedDiscount.map { "\($0)%" } ?? ""
        let alert = UIAlertController(
            title: "Success! 🎉",
            message: result.message + (discountText.isEmpty ? "" : "\nYou got \(discountText) off!"),
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Great!", style: .default))
        viewController.present(alert, animated: true)
        
        logPromoApplied(code: result.promoCode, discount: result.appliedDiscount)
    }
    
    private func showError(_ error: PromoError, from viewController: UIViewController) {
        let alert = UIAlertController(
            title: "Oops!",
            message: error.localizedDescription,
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        viewController.present(alert, animated: true)
        
        logPromoError(error: error)
    }
    
    private func promptLogin(from viewController: UIViewController) {
        let alert = UIAlertController(
            title: "Login Required",
            message: "Please log in to apply this promo code. The code will be applied after you log in.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Log In", style: .default) { _ in
            NotificationCenter.default.post(name: .showLoginScreen, object: nil)
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { [weak self] _ in
            self?.pendingPromoData = nil
        })
        viewController.present(alert, animated: true)
    }
    
    // MARK: - Analytics Logging
    
    private func logPromoLinkReceived(code: String, discount: Int) {
        print("[Analytics] Promo link received - code: \(code), discount: \(discount)%")
    }
    
    private func logPromoApplied(code: String?, discount: Int?) {
        print("[Analytics] Promo applied - code: \(code ?? "unknown"), discount: \(discount ?? 0)%")
    }
    
    private func logPromoError(error: PromoError) {
        print("[Analytics] Promo error - \(error.localizedDescription)")
    }
}

// MARK: - Notification Names

extension Notification.Name {
    static let showLoginScreen = Notification.Name("showLoginScreen")
    static let userDidLogin = Notification.Name("userDidLogin")
}

// MARK: - SceneDelegate Integration

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    let promoCoordinator = PromoCoordinator()
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        window = UIWindow(windowScene: windowScene)
        let rootVC = MainViewController()
        rootVC.promoCoordinator = promoCoordinator
        window?.rootViewController = UINavigationController(rootViewController: rootVC)
        window?.makeKeyAndVisible()
        
        if let urlContext = connectionOptions.urlContexts.first {
            handleIncomingURL(urlContext.url)
        }
        
        if let userActivity = connectionOptions.userActivities.first {
            handleUserActivity(userActivity)
        }
        
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(userDidLogin),
            name: .userDidLogin,
            object: nil
        )
    }
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        handleUserActivity(userActivity)
    }
    
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        guard let url = URLContexts.first?.url else { return }
        handleIncomingURL(url)
    }
    
    private func handleUserActivity(_ userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        handleIncomingURL(url)
    }
    
    private func handleIncomingURL(_ url: URL) {
        guard let rootNav = window?.rootViewController as? UINavigationController,
              let topVC = rootNav.topViewController else {
            return
        }
        promoCoordinator.handleUniversalLink(url, from: topVC)
    }
    
    @objc private func userDidLogin() {
        guard let rootNav = window?.rootViewController as? UINavigationController,
              let topVC = rootNav.topViewController else {
            return
        }
        promoCoordinator.handlePendingPromo(from: topVC)
    }
}

// MARK: - Main View Controller

class MainViewController: UIViewController {
    
    var promoCoordinator: PromoCoordinator?
    
    private let statusLabel: UILabel = {
        let label = UILabel()
        label.text = "Welcome! Open a promo link to get started."
        label.textAlignment = .center
        label.numberOfLines = 0
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let testButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Test Promo Link", for: .normal)
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "My App"
        view.backgroundColor = .systemBackground
        setupUI()
    }
    
    private func setupUI() {
        view.addSubview(statusLabel)
        view.addSubview(testButton)
        
        NSLayoutConstraint.activate([
            statusLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            statusLabel.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -40),
            statusLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            statusLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            testButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            testButton.topAnchor.constraint(equalTo: statusLabel.bottomAnchor, constant: 30)
        ])
        
        testButton.addTarget(self, action: #selector(testPromoLink), for: .touchUpInside)
    }
    
    @objc private func testPromoLink() {
        guard let url = URL(string: "https://myapp.com/promo?code=XYZ&discount=50") else { return }
        promoCoordinator?.handleUniversalLink(url, from: self)
    }
}

// MARK: - AppDelegate (for iOS 12 and below compatibility)

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    let promoCoordinator = PromoCoordinator()
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        return true
    }
    
    func application(_ application: UIApplication, configurationForConnecting connectingSceneSession: UISceneSession, options: UIScene.ConnectionOptions) -> UISceneConfiguration {
        return UISceneConfiguration(name: "Default Configuration", sessionRole: connectingSceneSession.role)
    }
    
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        if let rootNav = window?.rootViewController as? UINavigationController,
           let topVC = rootNav.topViewController {
            promoCoordinator.handleUniversalLink(url, from: topVC)
        }
        
        return true
    }
}